int _savingRecordEstimateSize(
  SavingRecord object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 + object.note.length * 3;
  bytesCount += 3 + object.wishUid.length * 3;
  return bytesCount;
}

void _savingRecordSerialize(
  SavingRecord object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeLong(offsets[0], object.amount);
  writer.writeDateTime(offsets[1], object.date);
  writer.writeString(offsets[2], object.note);
  writer.writeString(offsets[3], object.wishUid);
}

SavingRecord _savingRecordDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = SavingRecord();
  object.amount = reader.readLong(offsets[0]);
  object.date = reader.readDateTime(offsets[1]);
  object.id = id;
  object.note = reader.readString(offsets[2]);
  object.wishUid = reader.readString(offsets[3]);
  return object;
}

P _savingRecordDeserializeProp<P>(
  IsarReader reader,
